package projection

import (
	"fmt"
	"reflect"
	"sort"

	"cuelang.org/go/cue"
	"cuelang.org/go/cue/cuecontext"
	"cuelang.org/go/encoding/yaml"

	"github.com/verself/cue-renderer/internal/load"
)

// Header is the canonical comment block every renderer prepends to its
// output. Two lines: the universal "Code generated" warning and a Source
// pointer back to the CUE file or directory that owns the truth for the
// emitted artefact. Topology-driven renderers use Header directly;
// catalog-driven renderers (bazelmodule, bazelservertools) and the
// component-only clusters renderer use HeaderFor with their own source.
//
// Header does not include a YAML document marker — YAMLDocument
// appends `---\n` when the payload is YAML.
const Header = "# Code generated by src/cue-renderer; DO NOT EDIT.\n# Source: src/cue-renderer/instances/local\n"

// HeaderFor returns the canonical 2-line generated header pointing at
// `source` (a repo-relative CUE file or directory).
func HeaderFor(source string) string {
	return "# Code generated by src/cue-renderer; DO NOT EDIT.\n# Source: " + source + "\n"
}

const yamlSeparator = "---\n"

type NamedMap struct {
	Name  string
	Value map[string]any
	CUE   cue.Value
}

type ElectricComponent struct {
	ComponentName string
	ServiceName   string
	Port          any
	Sync          map[string]any
}

func GeneratedPath(name string) string {
	return "src/platform/ansible/group_vars/all/generated/" + name + ".yml"
}

func RenderedPath(target string) string {
	for len(target) > 0 && target[0] == '/' {
		target = target[1:]
	}
	return "src/platform/ansible/share/rendered/" + target
}

func YAMLDocument(payload any) ([]byte, error) {
	value := cuecontext.New().Encode(payload)
	if err := value.Err(); err != nil {
		return nil, fmt.Errorf("build YAML value: %w", err)
	}
	if err := value.Validate(cue.Concrete(true)); err != nil {
		return nil, fmt.Errorf("validate YAML value: %w", err)
	}
	body, err := yaml.Encode(value)
	if err != nil {
		return nil, fmt.Errorf("encode YAML: %w", err)
	}
	out := make([]byte, 0, len(Header)+len(yamlSeparator)+len(body))
	out = append(out, Header...)
	out = append(out, yamlSeparator...)
	out = append(out, body...)
	return out, nil
}

func WriteYAML(out interface{ WriteFile(string, []byte) error }, name string, payload any) error {
	doc, err := YAMLDocument(payload)
	if err != nil {
		return fmt.Errorf("render %s YAML: %w", name, err)
	}
	return out.WriteFile(GeneratedPath(name), doc)
}

func TopologyMap(loaded load.Loaded, key string) (map[string]any, error) {
	value := loaded.Value.LookupPath(cue.ParsePath(key))
	if err := value.Err(); err != nil {
		return nil, fmt.Errorf("lookup topology.%s: %w", key, err)
	}
	var out map[string]any
	if err := value.Decode(&out); err != nil {
		return nil, fmt.Errorf("decode topology.%s: %w", key, err)
	}
	return out, nil
}

func TopologySlice(loaded load.Loaded, key string) ([]any, error) {
	value := loaded.Value.LookupPath(cue.ParsePath(key))
	if err := value.Err(); err != nil {
		return nil, fmt.Errorf("lookup topology.%s: %w", key, err)
	}
	var out []any
	if err := value.Decode(&out); err != nil {
		return nil, fmt.Errorf("decode topology.%s: %w", key, err)
	}
	return out, nil
}

func ConfigMap(loaded load.Loaded, key string) (map[string]any, error) {
	return Map(loaded.ConfigMap, "config", key)
}

func Components(loaded load.Loaded) ([]NamedMap, error) {
	return NamedFields(loaded.Value, "components")
}

func NamedFields(root cue.Value, path string) ([]NamedMap, error) {
	value := root.LookupPath(cue.ParsePath(path))
	if err := value.Err(); err != nil {
		return nil, fmt.Errorf("lookup %s: %w", path, err)
	}
	iter, err := value.Fields()
	if err != nil {
		return nil, fmt.Errorf("fields %s: %w", path, err)
	}
	var out []NamedMap
	for iter.Next() {
		var decoded map[string]any
		if err := iter.Value().Decode(&decoded); err != nil {
			return nil, fmt.Errorf("decode %s.%s: %w", path, iter.Label(), err)
		}
		out = append(out, NamedMap{Name: iter.Label(), Value: decoded, CUE: iter.Value()})
	}
	return out, nil
}

func NestedFields(parent NamedMap, field string) ([]NamedMap, error) {
	if _, ok := parent.Value[field]; !ok {
		return nil, nil
	}
	return NamedFields(parent.CUE, field)
}

func EndpointWithAddresses(endpoint map[string]any) (map[string]any, error) {
	rendered := CloneMap(endpoint)
	host, err := String(rendered, "endpoint", "host")
	if err != nil {
		return nil, err
	}
	port, err := Int(rendered, "endpoint", "port")
	if err != nil {
		return nil, err
	}
	listenHost, err := OptionalString(rendered, "endpoint", "listen_host")
	if err != nil {
		return nil, err
	}
	if listenHost == "" {
		listenHost = host
	}
	rendered["address"] = fmt.Sprintf("%s:%d", host, port)
	rendered["bind_address"] = fmt.Sprintf("%s:%d", listenHost, port)
	return rendered, nil
}

func EndpointEntries(loaded load.Loaded) ([]map[string]any, error) {
	components, err := Components(loaded)
	if err != nil {
		return nil, err
	}
	var entries []map[string]any
	for _, component := range components {
		endpoints, err := NestedFields(component, "endpoints")
		if err != nil {
			return nil, err
		}
		for _, endpoint := range endpoints {
			entries = append(entries, map[string]any{
				"component": component.Name,
				"endpoint":  endpoint.Name,
				"port":      endpoint.Value["port"],
				"protocol":  endpoint.Value["protocol"],
				"exposure":  endpoint.Value["exposure"],
			})
		}
	}
	return entries, nil
}

func WorkloadIdentities(loaded load.Loaded) ([]map[string]any, error) {
	components, err := Components(loaded)
	if err != nil {
		return nil, err
	}
	trustDomain := loaded.Config.Spire.TrustDomain
	var out []map[string]any
	for _, component := range components {
		identities, err := NestedFields(component, "identities")
		if err != nil {
			return nil, err
		}
		for _, identity := range identities {
			path, err := String(identity.Value, identity.Name, "path")
			if err != nil {
				return nil, err
			}
			out = append(out, map[string]any{
				"key":                   component.Name + "." + identity.Name,
				"component":             component.Name,
				"name":                  identity.Name,
				"ansible_var":           identity.Value["ansible_var"],
				"entry_id":              identity.Value["entry_id"],
				"spiffe_id":             "spiffe://" + trustDomain + path,
				"user":                  identity.Value["user"],
				"group":                 identity.Value["group"],
				"uid_policy":            identity.Value["uid_policy"],
				"selector":              identity.Value["selector"],
				"x509_svid_ttl_seconds": identity.Value["x509_svid_ttl_seconds"],
				"restart_units":         identity.Value["restart_units"],
			})
		}
	}
	return out, nil
}

func Processes(loaded load.Loaded) ([]map[string]any, error) {
	components, err := Components(loaded)
	if err != nil {
		return nil, err
	}
	var rendered []map[string]any
	for _, component := range components {
		runtime, err := Map(component.Value, component.Name, "runtime")
		if err != nil {
			return nil, err
		}
		systemd, err := String(runtime, component.Name+".runtime", "systemd")
		if err != nil {
			return nil, err
		}
		endpoints, err := NestedFields(component, "endpoints")
		if err != nil {
			return nil, err
		}
		endpointNames := make([]string, 0, len(endpoints))
		for _, endpoint := range endpoints {
			endpointNames = append(endpointNames, endpoint.Name)
		}
		identities, err := NestedFields(component, "identities")
		if err != nil {
			return nil, err
		}
		identityNames := make([]string, 0, len(identities))
		for _, identity := range identities {
			identityNames = append(identityNames, identity.Name)
		}
		kind, err := String(component.Value, component.Name, "kind")
		if err != nil {
			return nil, err
		}
		rendered = append(rendered, map[string]any{
			"key":                  component.Name + ".primary",
			"component":            component.Name,
			"name":                 "primary",
			"systemd":              systemd,
			"user":                 runtime["user"],
			"group":                runtime["group"],
			"artifact":             component.Value["artifact"],
			"privileged":           kind == "privileged_daemon",
			"endpoints":            endpointNames,
			"identities":           identityNames,
			"after":                []string{},
			"wants":                []string{},
			"environment":          map[string]string{},
			"supplementary_groups": []string{},
			"requires_spiffe_sock": len(identityNames) > 0,
			"restart_units":        []string{systemd},
		})

		processes, err := NestedFields(component, "processes")
		if err != nil {
			return nil, err
		}
		for _, process := range processes {
			item := map[string]any{
				"key":                  component.Name + "." + process.Name,
				"component":            component.Name,
				"name":                 process.Name,
				"systemd":              process.Value["systemd"],
				"user":                 process.Value["user"],
				"group":                process.Value["group"],
				"artifact":             process.Value["artifact"],
				"privileged":           process.Value["privileged"],
				"endpoints":            process.Value["endpoints"],
				"identities":           process.Value["identities"],
				"after":                process.Value["after"],
				"wants":                process.Value["wants"],
				"environment":          process.Value["environment"],
				"supplementary_groups": process.Value["supplementary_groups"],
				"requires_spiffe_sock": process.Value["requires_spiffe_sock"],
				"restart_units":        process.Value["restart_units"],
			}
			if readinessEndpoint, ok := process.Value["readiness_endpoint"]; ok {
				item["readiness_endpoint"] = readinessEndpoint
			}
			rendered = append(rendered, item)
		}
	}
	return rendered, nil
}

func ElectricComponents(loaded load.Loaded) ([]ElectricComponent, error) {
	components, err := Components(loaded)
	if err != nil {
		return nil, err
	}
	var out []ElectricComponent
	for _, component := range components {
		syncAny, ok := component.Value["electric"]
		if !ok {
			continue
		}
		sync, ok := syncAny.(map[string]any)
		if !ok {
			return nil, fmt.Errorf("%s.electric: expected map, got %T", component.Name, syncAny)
		}
		interfaces, err := Map(component.Value, component.Name, "interfaces")
		if err != nil {
			return nil, err
		}
		shapeAPI, err := Map(interfaces, component.Name+".interfaces", "shape_api")
		if err != nil {
			return nil, err
		}
		endpointName, err := String(shapeAPI, component.Name+".interfaces.shape_api", "endpoint")
		if err != nil {
			return nil, err
		}
		endpoints, err := Map(component.Value, component.Name, "endpoints")
		if err != nil {
			return nil, err
		}
		endpoint, err := Map(endpoints, component.Name+".endpoints", endpointName)
		if err != nil {
			return nil, err
		}
		runtime, err := Map(component.Value, component.Name, "runtime")
		if err != nil {
			return nil, err
		}
		serviceName, err := String(runtime, component.Name+".runtime", "systemd")
		if err != nil {
			return nil, err
		}
		out = append(out, ElectricComponent{
			ComponentName: component.Name,
			ServiceName:   serviceName,
			Port:          endpoint["port"],
			Sync:          sync,
		})
	}
	return out, nil
}

func PostgresRoleConnectionLimits(loaded load.Loaded) (map[string]any, error) {
	components, err := Components(loaded)
	if err != nil {
		return nil, err
	}
	limits := map[string]any{}
	for _, component := range components {
		postgres, err := Map(component.Value, component.Name, "postgres")
		if err != nil {
			return nil, err
		}
		owner, err := String(postgres, component.Name+".postgres", "owner")
		if err != nil {
			return nil, err
		}
		limit, err := Int(postgres, component.Name+".postgres", "connection_limit")
		if err != nil {
			return nil, err
		}
		if owner != "" && limit > 0 {
			limits[owner] = limit
		}
	}
	electric, err := ElectricComponents(loaded)
	if err != nil {
		return nil, err
	}
	for _, component := range electric {
		role, err := String(component.Sync, component.ComponentName+".electric", "pg_role")
		if err != nil {
			return nil, err
		}
		limit, err := Int(component.Sync, component.ComponentName+".electric", "pg_conn_limit")
		if err != nil {
			return nil, err
		}
		limits[role] = limit
	}
	return limits, nil
}

func DeployArtifacts(loaded load.Loaded) ([]map[string]any, error) {
	components, err := Components(loaded)
	if err != nil {
		return nil, err
	}
	var rendered []map[string]any
	byOutput := map[string]map[string]any{}
	appendArtifact := func(componentName, source, name string, artifact map[string]any) error {
		kind, err := String(artifact, componentName+"."+source+"."+name+".artifact", "kind")
		if err != nil {
			return err
		}
		if kind == "none" {
			return nil
		}
		output, err := String(artifact, componentName+"."+source+"."+name+".artifact", "output")
		if err != nil {
			return err
		}
		item := map[string]any{
			"component": componentName,
			"source":    source,
			"name":      name,
			"artifact":  artifact,
		}
		if existing, ok := byOutput[output]; ok {
			if !reflect.DeepEqual(existing["artifact"], artifact) {
				return fmt.Errorf("deploy artifact output %s has conflicting definitions: %s.%s.%s and %s.%s.%s", output, existing["component"], existing["source"], existing["name"], componentName, source, name)
			}
			return nil
		}
		byOutput[output] = item
		rendered = append(rendered, item)
		return nil
	}
	for _, component := range components {
		artifact, err := Map(component.Value, component.Name, "artifact")
		if err != nil {
			return nil, err
		}
		if err := appendArtifact(component.Name, "component", "primary", artifact); err != nil {
			return nil, err
		}
		tools, err := NestedFields(component, "tools")
		if err != nil {
			return nil, err
		}
		for _, tool := range tools {
			if err := appendArtifact(component.Name, "tool", tool.Name, tool.Value); err != nil {
				return nil, err
			}
		}
		processes, err := NestedFields(component, "processes")
		if err != nil {
			return nil, err
		}
		for _, process := range processes {
			artifact, err := Map(process.Value, component.Name+".processes."+process.Name, "artifact")
			if err != nil {
				return nil, err
			}
			if err := appendArtifact(component.Name, "process", process.Name, artifact); err != nil {
				return nil, err
			}
		}
	}
	return rendered, nil
}

func CloneMap(in map[string]any) map[string]any {
	out := make(map[string]any, len(in))
	for k, v := range in {
		out[k] = v
	}
	return out
}

func Map(parent map[string]any, path, key string) (map[string]any, error) {
	value, ok := parent[key]
	if !ok {
		return nil, fmt.Errorf("%s.%s: missing", path, key)
	}
	out, ok := value.(map[string]any)
	if !ok {
		return nil, fmt.Errorf("%s.%s: expected map, got %T", path, key, value)
	}
	return out, nil
}

func Slice(parent map[string]any, path, key string) ([]any, error) {
	value, ok := parent[key]
	if !ok {
		return nil, fmt.Errorf("%s.%s: missing", path, key)
	}
	out, ok := value.([]any)
	if !ok {
		return nil, fmt.Errorf("%s.%s: expected slice, got %T", path, key, value)
	}
	return out, nil
}

func String(parent map[string]any, path, key string) (string, error) {
	value, ok := parent[key]
	if !ok {
		return "", fmt.Errorf("%s.%s: missing", path, key)
	}
	out, ok := value.(string)
	if !ok {
		return "", fmt.Errorf("%s.%s: expected string, got %T", path, key, value)
	}
	return out, nil
}

func OptionalString(parent map[string]any, path, key string) (string, error) {
	value, ok := parent[key]
	if !ok || value == nil {
		return "", nil
	}
	out, ok := value.(string)
	if !ok {
		return "", fmt.Errorf("%s.%s: expected string, got %T", path, key, value)
	}
	return out, nil
}

func Int(parent map[string]any, path, key string) (int64, error) {
	value, ok := parent[key]
	if !ok {
		return 0, fmt.Errorf("%s.%s: missing", path, key)
	}
	switch v := value.(type) {
	case int:
		return int64(v), nil
	case int64:
		return v, nil
	case float64:
		if v != float64(int64(v)) {
			return 0, fmt.Errorf("%s.%s: expected integer, got %v", path, key, v)
		}
		return int64(v), nil
	default:
		return 0, fmt.Errorf("%s.%s: expected integer, got %T", path, key, value)
	}
}

func SortedKeys(m map[string]any) []string {
	keys := make([]string, 0, len(m))
	for key := range m {
		keys = append(keys, key)
	}
	sort.Strings(keys)
	return keys
}

// StringList expects parent[key] to be []any of strings and returns the
// concrete []string slice. It mirrors String/Slice for cases where the
// caller wants a typed list at the leaves.
func StringList(parent map[string]any, path, key string) ([]string, error) {
	raw, err := Slice(parent, path, key)
	if err != nil {
		return nil, err
	}
	out := make([]string, 0, len(raw))
	for i, item := range raw {
		value, ok := item.(string)
		if !ok {
			return nil, fmt.Errorf("%s.%s[%d]: expected string, got %T", path, key, i, item)
		}
		out = append(out, value)
	}
	return out, nil
}

// OptionalStringList returns the typed []string at parent[key] or nil
// when the key is absent. Non-string elements are silently dropped to
// match the historical catalog-renderer behaviour.
func OptionalStringList(parent map[string]any, key string) []string {
	value, ok := parent[key]
	if !ok || value == nil {
		return nil
	}
	items, ok := value.([]any)
	if !ok {
		return nil
	}
	out := make([]string, 0, len(items))
	for _, item := range items {
		if value, ok := item.(string); ok {
			out = append(out, value)
		}
	}
	return out
}
